67	      customer: { yearsWithMHPCO: 0 },
68	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }],
69	    });
70	    expect(result).toEqual({ results: [{ premium: 137 }] });
