73	  // --- Modifier thresholds ---
74	  it("customer with exactly 2 years receives loyalty discount", () => {
75	    const result = runScenario({
76	      customer: { yearsWithMHPCO: 2 },
77	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0 }] }],
