113	        { op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0 }] },
114	        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }, { type: "rune" }, { type: "rune" }] },
