116	    });
117	    expect((result as { results: Array<{ premium: number }> }).results[1]).toEqual({ premium: 198 });
118	  });
119	  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G (MHPCO favor)");
120	  it.todo("intermediate amounts are kept as fractions; only the final premium/payout is rounded");
121	
122	  // --- Modifier scope on multi-item policies (❓ item-specific vs policy-wide) ---
123	  it.todo("policy with cursed sword (100 G base) + plain amulet (60 G base) has policy base 160 G; curse adds 50 G (50% of sword base, not policy total) → 210 G before further modifiers and fee");
124	  it.todo("item-specific modifiers (cursed, high enchantment) apply to the affected item's base premium");
125	  it.todo("policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium");
126	  it.todo("processing fee is added at the very end after all other modifiers");
127	
128	  // --- Integration example 1: Newcomer with cursed sword ---
129	  it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance = 160 + 5 fee)");
