1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const CURSED_RATE = 0.5;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const ITEM_BASE_PRICES: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; enchantment?: number; cursed?: boolean };
24	type Customer = { yearsWithMHPCO?: number };
25	type Scenario = {
26	  customer?: Customer;
27	  steps: { op: string; items: Item[] }[];
28	};
29	
30	function countItemsByType(items: Item[]): Map<string, number> {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	}
37	
38	function blockDiscountFor(type: string, count: number): number {
39	  const isComponent = COMPONENT_TYPES.has(type);
40	  const formsBlock = count === BLOCK_SIZE;
41	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
42	}
43	
44	function basePremiumForGroup(type: string, count: number): number {
45	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
46	}
47	
48	function computePolicyBase(items: Item[]): number {
49	  const itemCountsByType = countItemsByType(items);
50	  let basePremium = 0;
51	  for (const [type, count] of itemCountsByType.entries()) {
52	    basePremium += basePremiumForGroup(type, count);
53	  }
54	  return basePremium;
55	}
56	
57	function sumItemSurcharge(
58	  items: Item[],
59	  rate: number,
60	  applies: (item: Item) => boolean,
61	): number {
62	  return items
63	    .filter(applies)
64	    .reduce((sum, item) => sum + ITEM_BASE_PRICES[item.type] * rate, 0);
65	}
66	
67	function computeFirstInsuranceSurcharge(policyBase: number): number {
68	  return policyBase * FIRST_INSURANCE_RATE;
69	}
70	
71	function computeHighEnchantmentSurcharge(items: Item[]): number {
72	  return sumItemSurcharge(
73	    items,
74	    HIGH_ENCHANTMENT_RATE,
75	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
76	  );
77	}
78	
79	function computeCursedSurcharge(items: Item[]): number {
80	  return sumItemSurcharge(items, CURSED_RATE, (item) => item.cursed === true);
81	}
82	
83	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
84	  const years = customer.yearsWithMHPCO ?? 0;
85	  if (years >= LOYALTY_YEARS_THRESHOLD) {
86	    return policyBase * LOYALTY_DISCOUNT_RATE;
87	  }
88	  return 0;
89	}
90	
91	function computeFollowUpDiscount(policyBase: number, isFollowUpQuote: boolean): number {
92	  return isFollowUpQuote ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
93	}
94	
95	function computeQuotePremium(
96	  items: Item[],
97	  customer: Customer,
98	  isFollowUpQuote: boolean,
99	): number {
100	  const policyBase = computePolicyBase(items);
101	  const premium =
102	    policyBase +
103	    computeHighEnchantmentSurcharge(items) +
104	    computeCursedSurcharge(items) +
105	    computeFirstInsuranceSurcharge(policyBase) -
106	    computeLoyaltyDiscount(policyBase, customer) -
107	    computeFollowUpDiscount(policyBase, isFollowUpQuote) +
108	    PROCESSING_FEE;
109	  return Math.ceil(premium);
110	}
111	
112	export function runScenario(scenario: unknown): unknown {
113	  const s = scenario as Scenario;
114	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
115	
116	  const results = s.steps.map((step, index) => ({
117	    premium: computeQuotePremium(step.items, customer, index > 0),
118	  }));
119	  return { results };
120	}
